const AllColorized = () => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
        {['alice', 'bob', 'carol', 'dave', 'eve', 'frank', 'grace', 'henry', 'iris'].map(name => (
            <Avatar key={name} size="lg" colorize={name} fallback={name.slice(0, 2).toUpperCase()} />
        ))}
    </div>
);

const AllSizes = () => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
        {(['xs', 'sm', 'md', 'lg', 'xl', '2xl', '3xl', '4xl'] as const).map(size => (
            <Avatar key={size} size={size} fallback={size.toUpperCase()} />
        ))}
    </div>
);

const AllSizesWithImage = () => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
        {(['xs', 'sm', 'md', 'lg', 'xl', '2xl', '3xl', '4xl'] as const).map(size => (
            <Avatar
                key={size}
                size={size}
                src="https://images.unsplash.com/photo-1502823403499-6ccfcf4fb453?&w=256&h=256&q=70&crop=focalpoint&fp-x=0.5&fp-y=0.3&fp-z=1&fit=crop"
                alt="Alex Morgan"
                fallback="AM"
            />
        ))}
    </div>
);

const AllVariants = () => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
        {(['circle', 'square', 'pillow', 'pentagon'] as const).map(variant => (
            <Avatar
                key={variant}
                size="lg"
                variant={variant}
                fallback={variant.slice(0, 2).toUpperCase()}
            />
        ))}
    </div>
);

const AllVariantsWithImage = () => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
        {(['circle', 'square', 'pillow', 'pentagon'] as const).map(variant => (
            <Avatar
                key={variant}
                size="lg"
                variant={variant}
                src="https://images.unsplash.com/photo-1502823403499-6ccfcf4fb453?&w=256&h=256&q=70&crop=focalpoint&fp-x=0.5&fp-y=0.3&fp-z=1&fit=crop"
                alt="Alex Morgan"
                fallback="AM"
            />
        ))}
    </div>
);

const Variants = () => (
    <Row>
        {VARIANTS.map(variant => (
            <Button key={variant} variant={variant}>
                {TEXT}
            </Button>
        ))}
    </Row>
);

const Sizes = () => (
    <Row>
        {SIZES.map(size => (
            <Button key={size} size={size}>
                {TEXT}
            </Button>
        ))}
    </Row>
);

const Disabled = () => (
    <Row>
        {VARIANTS.map(variant => (
            <Button asChild key={variant} variant={variant} disabled>
                <a>{TEXT}</a>
            </Button>
        ))}
    </Row>
);

const WithIcons = () => (
    <Stack>
        {VARIANTS.map(variant => (
            <Row key={variant}>
                {SIZES.map(size => (
                    <Button key={size} variant={variant} size={size}>
                        <IconAdd />
                        {TEXT}
                        <IconAdd />
                    </Button>
                ))}
            </Row>
        ))}
    </Stack>
);

const OnlyIcon = () => (
    <Stack>
        {NON_LINK_VARIANTS.map(variant => (
            <Row key={variant}>
                {SIZES.map(size => (
                    <Button key={size} variant={variant} size={size} aria-label="Close">
                        <IconClose />
                    </Button>
                ))}
            </Row>
        ))}
    </Stack>
);

const Loading = () => (
    <Stack>
        {NON_LINK_VARIANTS.map(variant => (
            <Row key={variant}>
                {SIZES.map(size => (
                    <div key={size} style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                        <Button variant={variant} size={size} loading aria-label="Loading">
                            <IconAdd />
                        </Button>
                        <Button variant={variant} size={size} loading>
                            {TEXT}
                        </Button>
                    </div>
                ))}
            </Row>
        ))}
    </Stack>
);

const Status = () => (
    <Stack>
        <Row>
            {VARIANTS.map(variant => (
                <Button key={variant} variant={variant} status="danger">
                    <IconAdd />
                    {TEXT}
                    <IconAdd />
                </Button>
            ))}
        </Row>
        <Row>
            {VARIANTS.map(variant => (
                <Button asChild key={variant} variant={variant} status="danger" disabled>
                    <a>
                        <IconAdd />
                        {TEXT}
                        <IconAdd />
                    </a>
                </Button>
            ))}
        </Row>
    </Stack>
);

const Rounded = () => (
    <Stack>
        {NON_LINK_VARIANTS.map(variant => (
            <Row key={variant}>
                {SIZES.map(size => (
                    <Button key={size} variant={variant} size={size} rounded>
                        <IconAdd />
                        {TEXT}
                        <IconAdd />
                    </Button>
                ))}
            </Row>
        ))}
    </Stack>
);

const Sizes = () => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '2rem' }}>
        {(['sm', 'md', 'lg'] as const).map(size => (
            <Loading key={size} size={size} />
        ))}
    </div>
);

const OnDarkSurface = () => (
    <div className="flex items-center gap-8 rounded-lg bg-bg-button-primary-enable p-8 text-text-default-base-inverse-primary">
        <Loading size="sm" />
        <Loading size="md" />
        <Loading size="lg" />
    </div>
);
